var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"콜록! 콜록! 에취!","JPN":"ゲホッ！　ゲホッ！　くしゅん！","ENG":"*Cough!* *Cough!* Achoo!","TWN":"咳咳！咳咳！哈啾！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"셰나의 핵을 찾겠다니, 이건 어리석은 짓이야, 루나….","JPN":"シェナの核を探すなんて時間の無駄よ、ルナ……","ENG":"Luna, it's foolish to try to find Shena's core...","TWN":"露娜，怎麼可能找得到世娜的核心呢，你這是徒勞……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"관리국이 내버려 두고 갈 리 없어.","JPN":"管理局が置いて行くはずがないじゃない。","ENG":"The Administration wouldn't have left without it.","TWN":"一定被管理局拿走了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"혹시 모르잖아. 그렇게 난장판이 벌어졌는데. 부스러기라도 남아 있을지.","JPN":"でも、わかんないじゃん。あんだけ修羅場だったんだから、欠片でも残ってるかもしれない。","ENG":"You never know. After all the chaos that happened here, there might be a tiny shard of it left.","TWN":"你怎麼知道，當時情況那麼混亂，或許還有留下一些呢。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그리고 루나님!","JPN":"それに、ルナ様！","ENG":"And it's Ms. Luna to you!","TWN":"然後，要叫我露娜大人！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지휘자님을 쓰러뜨린 날 부를 때는 반드시 님 자를 붙이도록 하라구!","JPN":"マエストロを倒したアタシのことを呼ぶ時には、必ず「様」をつけてよ！","ENG":"I defeated the Chief Conductor, so you have to address me as Ms. Luna from now on!","TWN":"我是打敗指揮家的人，叫我的時候一定要加上大人二個字！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"귀에 익은 소리가 들린다.","JPN":"聞きなれた音が聞こえる。","ENG":"I hear a familiar sound.","TWN":"聽到熟悉的聲音。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"증오스럽고도, 가증스러운.","JPN":"憎たらしく、卑劣で。","ENG":"A piece of music.","TWN":"可恨、又可惡的曲子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"그럼에도 이제는 아무런 감흥도 없는.","JPN":"でも今は何の興味も湧いてこないような。","ENG":"That is hateful and abominable.","TWN":"但對於這種曲子，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"그런 악곡.","JPN":"そんな楽曲が。","ENG":"But no longer elicits any feelings.","TWN":"我現在已經毫無興致。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"아아…….","JPN":"ああ……","ENG":"Ah...","TWN":"啊啊……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕이시여, 마침내 깊은 잠에서 눈을 뜨셨군요.","JPN":"王よ、ついに深き眠りより目覚められたのですね。","ENG":"My queen. You have finally awakened from your slumber.","TWN":"我的王，您終於從長眠中甦醒過來。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"아주 예전부터…….","JPN":"遠い昔から……","ENG":"I've been hearing this sound...","TWN":"從很久之前……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"마음에 들지 않았던 소리가 들려왔어요, 언니.","JPN":"気に入らなかった音が聞こえてきました、お姉ちゃん。","ENG":"That has been bothering me for a long time, Sis.","TWN":"我就聽到一個很不悅耳的聲音，姊姊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"저 밖에서는 가증스러운 악단이 활개를 치고 있나이다.","JPN":"外には、あの憎き楽団がのさばっております。","ENG":"Outside, the abominable Orchestra plucks its strings and toots its horns.","TWN":"可恨的樂團依然在那外面猖獗。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"제 힘이 부족하여 저 가증스러운 봉인을 어쩌지 못하였으나….","JPN":"私の力不足ゆえ、あの憎き封印を解くこと叶いませんでしたが……","ENG":"With my lack of strength, there was nothing I could do about the despicable seal...","TWN":"都怪我無能，沒有能解除那該死的封印……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕께서 나아가신다면, 저들이 어찌 위세를 발휘하겠나이까.","JPN":"王自らお出ましとあらば、あやつらが威勢を張ることはもはや不可能でしょう。","ENG":"However, they wouldn't wield their power if our queen advanced on the stage.","TWN":"但如果王親自上陣，一定能挫挫他們的銳氣。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"엘리시움 필하모닉…….","JPN":"エリシウムフィルハーモニー……","ENG":"Elysium Philharmonic...","TWN":"愛樂組織……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"그래. <color=#ffd34c>그 여자</color>도 그 이름을 말했어요.","JPN":"そう。<color=#ffd34c>あの女</color>もその名前を口にしていました。","ENG":"Yes. <color=#ffd34c>That woman</color> also said that name.","TWN":"沒錯。<color=#ffd34c>那個女人</color>也提過這個名字。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하오면…?","JPN":"と、おっしゃいますと……？","ENG":"And...?","TWN":"那麼您……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"초대에 기꺼이 응해야겠네요.","JPN":"喜んで招待に応じないといけませんね。","ENG":"I will gladly accept the invitation.","TWN":"我會很高興地接受這個邀請。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"다른 언니들에게도 전해 주세요.","JPN":"他のお姉ちゃんたちにも伝えてください。","ENG":"Tell the other sisters as well.","TWN":"也告訴其他姊姊吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};